<script lang="ts" setup>
import { ref, reactive, computed } from 'vue';
import { StandardListTemplate, StandardDetailTemplate } from '@/components/templates';
import ContentHeader from '@/components/common/contentHeader/ContentHeader.vue';
import { SearchForm, SearchFormRow, SearchFormLabel, SearchFormField, SearchFormContent } from '@/components/common/searchForm';
import { DataTable } from '@/components/common/dataTable2';
import Paginator from '@/components/common/paginator/Paginator.vue';
import Column from 'primevue/column';
import { Button } from '@/components/common/button';
import { InputText } from '@/components/common/inputText';
import { RangeDatePicker } from '@/components/common/datePicker';
import { DotStatusText } from '@/components/common/dotStatusText';

// ─────────────────── Types ──────────────────────────────────────────────────
interface RowItem {
  id: number;
  title: string;
  status: string;
  statusNm: string;
  statusColor: string;
  regDt: string;
}

// ─────────────────── Mock Data (API 연동 전 임시) ────────────────────────────
const MOCK_DATA: RowItem[] = [
  { id: 1, title: '제목 1번 항목', status: 'RECV', statusNm: '접수', statusColor: 'blue', regDt: '2024-01-01' },
  { id: 2, title: '제목 2번 항목', status: 'WIP', statusNm: '처리중', statusColor: 'orange', regDt: '2024-02-02' },
  { id: 3, title: '제목 3번 항목', status: 'DONE', statusNm: '완료', statusColor: 'green', regDt: '2024-03-03' },
  { id: 4, title: '제목 4번 항목', status: 'RECV', statusNm: '접수', statusColor: 'blue', regDt: '2024-04-04' },
  { id: 5, title: '제목 5번 항목', status: 'WIP', statusNm: '처리중', statusColor: 'orange', regDt: '2024-05-05' },
  { id: 6, title: '제목 6번 항목', status: 'DONE', statusNm: '완료', statusColor: 'green', regDt: '2024-06-06' },
  { id: 7, title: '제목 7번 항목', status: 'RECV', statusNm: '접수', statusColor: 'blue', regDt: '2024-07-07' },
  { id: 8, title: '제목 8번 항목', status: 'WIP', statusNm: '처리중', statusColor: 'orange', regDt: '2024-08-08' },
  { id: 9, title: '제목 9번 항목', status: 'DONE', statusNm: '완료', statusColor: 'green', regDt: '2024-09-09' },
  { id: 10, title: '제목 10번 항목', status: 'RECV', statusNm: '접수', statusColor: 'blue', regDt: '2024-10-10' },
  { id: 11, title: '제목 11번 항목', status: 'WIP', statusNm: '처리중', statusColor: 'orange', regDt: '2024-11-11' },
  { id: 12, title: '제목 12번 항목', status: 'DONE', statusNm: '완료', statusColor: 'green', regDt: '2024-12-12' },
  { id: 13, title: '제목 13번 항목', status: 'RECV', statusNm: '접수', statusColor: 'blue', regDt: '2024-01-13' },
  { id: 14, title: '제목 14번 항목', status: 'WIP', statusNm: '처리중', statusColor: 'orange', regDt: '2024-02-14' },
  { id: 15, title: '제목 15번 항목', status: 'DONE', statusNm: '완료', statusColor: 'green', regDt: '2024-03-15' },
  { id: 16, title: '제목 16번 항목', status: 'RECV', statusNm: '접수', statusColor: 'blue', regDt: '2024-04-16' },
  { id: 17, title: '제목 17번 항목', status: 'WIP', statusNm: '처리중', statusColor: 'orange', regDt: '2024-05-17' },
  { id: 18, title: '제목 18번 항목', status: 'DONE', statusNm: '완료', statusColor: 'green', regDt: '2024-06-18' },
  { id: 19, title: '제목 19번 항목', status: 'RECV', statusNm: '접수', statusColor: 'blue', regDt: '2024-07-19' },
  { id: 20, title: '제목 20번 항목', status: 'WIP', statusNm: '처리중', statusColor: 'orange', regDt: '2024-08-20' },
];

// ─────────────────── Options ────────────────────────────────────────────────
const statusOptions = [
  { label: '전체', value: '' },
  { label: '접수', value: 'RECV', color: 'blue' },
  { label: '처리중', value: 'WIP', color: 'orange' },
  { label: '완료', value: 'DONE', color: 'green' },
];

// ─────────────────── State ──────────────────────────────────────────────────
const allRows = ref<RowItem[]>([...MOCK_DATA]);

const state = reactive({
  loading:     false,
  selectedRow: null as RowItem | null,
  pageSize:    20,
  page:        { first: 0, rows: 20 },
});

const searchParams = reactive({
  title: '',
  status: '',
  regDtFrom: '',
  regDtTo: '',
});

// ─────────────────── Computed ───────────────────────────────────────────────
const filteredRows = computed<RowItem[]>(() => {
  let rows = allRows.value;
  if (searchParams.title) rows = rows.filter(r => r.title.includes(searchParams.title));
  if (searchParams.status) rows = rows.filter(r => r.status === searchParams.status);
  if (searchParams.regDtFrom) rows = rows.filter(r => r.regDt >= searchParams.regDtFrom);
  if (searchParams.regDtTo)   rows = rows.filter(r => r.regDt <= searchParams.regDtTo);
  return rows;
});

const pagedRows = computed<RowItem[]>(() =>
  filteredRows.value.slice(state.page.first, state.page.first + state.pageSize)
);

// ─────────────────── Handlers ───────────────────────────────────────────────
function onSearch(): void {
  state.page        = { first: 0, rows: state.pageSize };
  state.selectedRow = null;
}

function onReset(): void {
  Object.assign(searchParams, { title: '', status: '', regDtFrom: '', regDtTo: '' });
  onSearch();
}

function onRowSelect(event: { data: RowItem }): void {
  state.selectedRow = event.data;
}

function onPageChange(event: { first: number; rows: number }): void {
  state.page = event;
}

function onEdit(): void {
  // TODO: 수정 화면으로 이동 또는 모달 오픈
  console.log('[scaffold] onEdit →', state.selectedRow);
}

function onDelete(): void {
  if (!state.selectedRow) return;
  allRows.value     = allRows.value.filter(r => r.id !== state.selectedRow!.id);
  state.selectedRow = null;
}
</script>
